   103→function generateSafeInterpretation(demographics: any, context: any, labs: any[]): any {
   104→  console.log('[API] Generating safe interpretation for guest labs:', labs.map(l => l.name));
   105→  
   106→  // Create flags based on actual lab values and reference ranges
   107→  const flags = labs.map(lab => {
   108→    let severity = 'normal';
   109→    let finding = 'Within normal range';
   110→    let description = `${lab.name} is within the normal range.`;
   111→    let actionableRecommendation = '';
   112→    
   113→    // Check if value is outside reference range
   114→    if (lab.ref_range_low && lab.ref_range_high) {
   115→      if (lab.value < lab.ref_range_low) {
   116→        severity = 'low';
   117→        finding = 'Below normal range';
   118→        description = `${lab.name} is lower than the normal range. This might indicate a deficiency or other health concern that should be discussed with your doctor.`;
   119→        actionableRecommendation = generateActionableRecommendation(lab, 'low', demographics);
   120→      } else if (lab.value > lab.ref_range_high) {
   121→        severity = 'high';
   122→        finding = 'Above normal range';
   123→        description = `${lab.name} is higher than the normal range. This might indicate an excess or other health concern that should be discussed with your doctor.`;
   124→        actionableRecommendation = generateActionableRecommendation(lab, 'high', demographics);
   125→      }
   126→    }
   127→    
   128→    return {
   129→      severity,
   130→      lab_code: lab.code,
   131→      lab_name: lab.name,
   132→      finding,
   133→      description,
   134→      actionableRecommendation
   135→    };
   136→  });
   137→  
   138→  // Create enhanced summary with onboarding information
   139→  const abnormalLabs = flags.filter(f => f.severity !== 'normal');
   140→  const normalLabs = flags.filter(f => f.severity === 'normal');
   141→  
   142→  const summary = generateEnhancedSummary(abnormalLabs, normalLabs, demographics, labs);
   143→  
   144→  // Generate targeted lifestyle recommendations based on actual flags and demographics
   145→  const lifestyle = generateEnhancedLifestyleRecommendations(abnormalLabs, demographics, labs);
   146→  
   147→  // Generate supplement recommendations based on key flags
   148→  const supplements = generateEnhancedSupplementRecommendations(abnormalLabs, demographics, labs);
   149→  
   150→  return {
   151→    summary,
   152→    flags,
   153→    lifestyle,
   154→    supplements,
   155→    doctor_questions: [
   156→      'Are there any specific lifestyle changes I should consider based on these results?',
