   163→/**
   164→ * Generate actionable recommendations for flagged markers
   165→ */
   166→function generateActionableRecommendation(lab: any, severity: 'low' | 'high', demographics: any): string {
   167→  const markerCode = lab.code.toLowerCase();
   168→  const markerName = lab.name.toLowerCase();
   169→  
   170→  // Iron-related markers
   171→  if (markerCode.includes('hgb') || markerCode.includes('hemoglobin') || 
   172→      markerCode.includes('hct') || markerCode.includes('hematocrit') ||
   173→      markerCode.includes('mch') || markerCode.includes('mcv') ||
   174→      markerCode.includes('ferritin') || markerCode.includes('iron')) {
   175→    if (severity === 'low') {
   176→      return 'Consider iron-rich foods (lean meats, spinach, beans) and discuss iron supplementation with your doctor.';
   177→    }
   178→  }
   179→  
   180→  // Vitamin D
   181→  if (markerCode.includes('vitamin d') || markerCode.includes('25-oh') || markerCode.includes('d3')) {
   182→    if (severity === 'low') {
   183→      return 'Increase sun exposure (10-15 minutes daily) and consider Vitamin D3 supplementation (1000-2000 IU daily).';
   184→    }
   185→  }
   186→  
   187→  // B12
   188→  if (markerCode.includes('b12') || markerCode.includes('cobalamin')) {
   189→    if (severity === 'low') {
   190→      return 'Include B12-rich foods (fish, meat, dairy) and consider B12 supplementation or injections.';
   191→    }
   192→  }
   193→  
