import { NextRequest, NextResponse } from 'next/server';

// This is needed for App Router
export const dynamic = 'force-dynamic';

interface ProcessCompleteRequest {
  demographics: {
    age: number;
    sex: string;
    height?: number;
    weight?: number;
    pregnant?: boolean;
    medical_conditions?: string[];
    medications?: string[];
  };
  context?: {
    reason: string;
    symptoms: string[];
    concerns: string[];
  };
  labs: Array<{
    code: string;
    name: string;
    value: number;
    unit: string;
    value_si: number;
    unit_si: string;
    ref_range_low?: number;
    ref_range_high?: number;
    category?: string;
  }>;
  consent?: {
    consent: boolean;
    timestamp: string;
  };
}

interface ProcessCompleteResponse {
  success: boolean;
  data?: {
    demographics: any;
    labs: any[];
    interpretation: any;
  };
  message?: string;
}

export async function POST(request: NextRequest): Promise<NextResponse<ProcessCompleteResponse>> {
  try {
    console.log('[API] Guest process-complete request received');

    const body: ProcessCompleteRequest = await request.json();
    const { demographics, labs, context, consent } = body;

    // Validate required fields
    if (!labs || labs.length === 0) {
      return NextResponse.json({ 
        success: false,
        message: 'No lab data provided' 
      }, { status: 400 });
    }

    if (!demographics) {
      return NextResponse.json({ 
        success: false,
        message: 'Demographics required' 
      }, { status: 400 });
    }

    console.log('[API] Processing guest request with:', {
      labsCount: labs.length,
      demographics: demographics.age + 'yo ' + demographics.sex
    });

    console.log('[API] Generating SAFE interpretation for guest user');

    // Generate interpretation using the same logic as authenticated users
    const interpretation = generateSafeInterpretation(demographics, context, labs);

    console.log('[API] Generated interpretation for guest user');

    return NextResponse.json({
      success: true,
      data: {
        demographics,
        labs,
        interpretation
      }
    });

  } catch (error) {
    console.error('[API] Error in guest process-complete:', error);
    return NextResponse.json({
      success: false,
      message: 'Internal server error'
    }, { status: 500 });
  }
}

/**
 * Generate SAFE interpretation without AI hallucination (same as authenticated users)
 */
function generateSafeInterpretation(demographics: any, context: any, labs: any[]): any {
  console.log('[API] Generating safe interpretation for guest labs:', labs.map(l => l.name));

  // Create flags based on actual lab values and reference ranges
  const flags = labs.map(lab => {
    let severity = 'normal';
    let finding = 'Within normal range';
    let description = `${lab.name} is within the normal range.`;
    let actionableRecommendation = '';

    // Check if value is outside reference range
    if (lab.ref_range_low && lab.ref_range_high) {
      if (lab.value < lab.ref_range_low) {
        severity = 'low';
        finding = 'Below normal range';
        description = `${lab.name} is lower than the normal range. This might indicate a deficiency or other health concern that should be discussed with your doctor.`;
        actionableRecommendation = generateActionableRecommendation(lab, 'low', demographics);
      } else if (lab.value > lab.ref_range_high) {
        severity = 'high';
        finding = 'Above normal range';
        description = `${lab.name} is higher than the normal range. This might indicate an excess or other health concern that should be discussed with your doctor.`;
        actionableRecommendation = generateActionableRecommendation(lab, 'high', demographics);
      }
    }

    return {
      severity,
      lab_code: lab.code,
      lab_name: lab.name,
      finding,
      description,
      actionableRecommendation
    };
  });

  // Create enhanced summary with onboarding information
  const abnormalLabs = flags.filter(f => f.severity !== 'normal');
  const normalLabs = flags.filter(f => f.severity === 'normal');

  const summary = generateEnhancedSummary(abnormalLabs, normalLabs, demographics, labs);

  // Generate targeted lifestyle recommendations based on actual flags and demographics
  const lifestyle = generateEnhancedLifestyleRecommendations(abnormalLabs, demographics, labs);

  // Generate supplement recommendations based on key flags
  const supplements = generateEnhancedSupplementRecommendations(abnormalLabs, demographics, labs);

  return {
    summary,
    flags,
    lifestyle,
    supplements,
    doctor_questions: [
      'Are there any specific lifestyle changes I should consider based on these results?',
      'When should I have my next lab test?',
      'Do these results require any follow-up testing?'
    ]
  };
}

/**
 * Generate actionable recommendations for flagged markers
 */
function generateActionableRecommendation(lab: any, severity: 'low' | 'high', demographics: any): string {
  const markerCode = lab.code.toLowerCase();
  const markerName = lab.name.toLowerCase();

  // Iron-related markers
  if (markerCode.includes('hgb') || markerCode.includes('hemoglobin') || 
      markerCode.includes('hct') || markerCode.includes('hematocrit') ||
      markerCode.includes('mch') || markerCode.includes('mcv') ||
      markerCode.includes('ferritin') || markerCode.includes('iron')) {
    if (severity === 'low') {
      return 'Consider iron-rich foods (lean meats, spinach, beans) and discuss iron supplementation with your doctor.';
    }
  }

  // Vitamin D
  if (markerCode.includes('vitamin d') || markerCode.includes('25-oh') || markerCode.includes('d3')) {
    if (severity === 'low') {
      return 'Increase sun exposure (10-15 minutes daily) and consider Vitamin D3 supplementation (1000-2000 IU daily).';
    }
  }

  // B12
  if (markerCode.includes('b12') || markerCode.includes('cobalamin')) {
    if (severity === 'low') {
      return 'Include B12-rich foods (fish, meat, dairy) and consider B12 supplementation or injections.';
    }
  }

  // Folate
  if (markerCode.includes('folate') || markerCode.includes('folic acid')) {
    if (severity === 'low') {
      return 'Increase folate-rich foods (leafy greens, citrus fruits, beans) and consider folic acid supplementation.';
    }
  }

  // Cholesterol
  if (markerCode.includes('cholesterol') || markerCode.includes('ldl') || markerCode.includes('hdl')) {
    if (severity === 'high') {
      return 'Focus on heart-healthy diet (reduce saturated fats, increase fiber) and regular exercise.';
    }
  }

  // Blood sugar/Glucose
  if (markerCode.includes('glucose') || markerCode.includes('sugar')) {
    if (severity === 'high') {
      return 'Limit refined carbohydrates, increase fiber intake, and maintain regular meal timing.';
    }
  }

  // Thyroid
  if (markerCode.includes('tsh') || markerCode.includes('thyroid')) {
    if (severity === 'high') {
      return 'Discuss thyroid function with your doctor. Consider iodine-rich foods (seaweed, fish) and manage stress.';
    }
  }

  // Liver enzymes
  if (markerCode.includes('ast') || markerCode.includes('alt') || markerCode.includes('liver')) {
    if (severity === 'high') {
      return 'Limit alcohol consumption, avoid processed foods, and consider liver-supporting foods (beets, leafy greens).';
    }
  }

  // Kidney function
  if (markerCode.includes('creatinine') || markerCode.includes('bun') || markerCode.includes('kidney')) {
    if (severity === 'high') {
      return 'Stay well-hydrated, limit protein intake if recommended by doctor, and monitor blood pressure.';
    }
  }

  // General recommendations
  if (severity === 'low') {
    return 'Discuss potential causes with your doctor and consider targeted supplementation or dietary changes.';
  } else {
    return 'Work with your doctor to identify underlying causes and develop a management plan.';
  }
}

/**
 * Generate enhanced summary with onboarding information
 */
function generateEnhancedSummary(abnormalLabs: any[], normalLabs: any[], demographics: any, labs: any[]): string {
  const age = demographics?.age;
  const sex = demographics?.sex;
  const hasConditions = demographics?.medical_conditions?.length > 0;
  const hasMedications = demographics?.medications?.length > 0;

  let summary = '';

  // Overall health assessment paragraph
  if (abnormalLabs.length === 0) {
    summary += `Your lab results show excellent overall health with all tested markers (${labs.map(l => l.name).join(', ')}) within normal ranges. `;
  } else if (abnormalLabs.length === 1) {
    summary += `Your lab results indicate generally good health with one marker requiring attention: ${abnormalLabs[0].lab_name} is ${abnormalLabs[0].severity === 'high' ? 'elevated' : 'below normal'}. `;
  } else {
    summary += `Your lab results show ${abnormalLabs.length} markers that require attention: ${abnormalLabs.map(f => f.lab_name).join(', ')}. `;
  }

  // Age and sex considerations
  if (age && sex) {
    if (age >= 50) {
      summary += `As a ${age}-year-old ${sex.toLowerCase()}, regular monitoring of these markers becomes increasingly important for maintaining long-term health. `;
    } else if (age >= 30) {
      summary += `At ${age} years old, these results provide a good baseline for tracking your health trends over time. `;
    } else {
      summary += `At ${age} years old, these results establish an important baseline for your future health monitoring. `;
    }
  }

  // Medical conditions context
  if (hasConditions) {
    summary += `Given your existing medical conditions (${demographics.medical_conditions.join(', ')}), these results should be interpreted in that context and discussed with your healthcare provider. `;
  }

  // Medication considerations
  if (hasMedications) {
    summary += `Your current medications (${demographics.medications.join(', ')}) may influence some of these results, so it's important to review them with your doctor. `;
  }

  // Action-oriented conclusion
  if (abnormalLabs.length === 0) {
    summary += `Continue maintaining your healthy lifestyle with regular exercise, balanced nutrition, and routine health checkups.`;
  } else {
