                              other: "bg-gray-50 border-gray-200 text-gray-800"
                            }

                            const typeIcons = {
                              diet: Heart,
                              exercise: Activity,
                              sleep: Brain,
                              stress: AlertTriangle,
                              supplements: Zap,
                              other: Info
                            }

                            const IconComponent = typeIcons[rec.type as keyof typeof typeIcons]

                            return (
                              <div key={index} className={`p-4 rounded-lg border ${typeColors[rec.type as keyof typeof typeColors]}`}>
                                <h4 className="font-semibold mb-2 flex items-center gap-2">
                                  <IconComponent className="h-5 w-5" />
                                  {rec.type.charAt(0).toUpperCase() + rec.type.slice(1)}
                                </h4>
                                <p className="text-sm mb-2">{rec.recommendation}</p>
                                <p className="text-xs opacity-75">
                                  <strong>Evidence:</strong> {rec.evidence}
                                </p>
                              </div>
                            )
                          })
                        ) : (
                          <div className="p-4 rounded-lg bg-green-50 border border-green-200">
                            <h4 className="font-semibold mb-2 text-green-800 flex items-center gap-2">
                              <Heart className="h-5 w-5 text-green-600" />
                              General Health
                            </h4>
                            <ul className="text-sm text-green-700 space-y-1">
                              <li>• Regular physical activity - aim for 150 minutes weekly</li>
                              <li>• Balanced diet with plenty of fruits, vegetables, and whole grains</li>
                              <li>• Adequate sleep (7-9 hours) for overall health</li>
                            </ul>
                          </div>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                </TabsContent>

                <TabsContent value="supplements" className="space-y-4">
                  <Card>
                    <CardHeader>
                      <CardTitle>AI-Generated Supplement Recommendations</CardTitle>
                      <CardDescription>
                        Personalized supplement suggestions based on your lab results (not medical advice)
                      </CardDescription>
                    </CardHeader>
                    <CardContent className="max-h-96 overflow-y-auto">
                      <Alert className="mb-6 border-red-200 bg-red-50">
                        <AlertTriangle className="h-4 w-4 text-red-600" />
                        <AlertDescription className="text-red-800">
                          <strong className="text-red-900">Important:</strong> Always consult your healthcare provider
                          before starting any supplements. This is educational information only and not medical advice.
                        </AlertDescription>
                      </Alert>

                      <div className="space-y-4">
                        {labSet.interpretation?.lifestyle && labSet.interpretation.lifestyle.filter((rec: any) => rec.type === 'supplements').length > 0 ? (
                          labSet.interpretation.lifestyle
                            .filter((rec: any) => rec.type === 'supplements')
                            .map((rec: any, index: number) => (
                              <div key={index} className="p-4 rounded-lg border bg-gradient-to-r from-yellow-50 to-orange-50 border-yellow-200">
                                <h4 className="font-semibold mb-2 flex items-center gap-2 text-yellow-800">
                                  <Zap className="h-5 w-5 text-yellow-600" />
                                  Supplement Recommendation
                                </h4>
                                <p className="text-sm mb-2">{rec.recommendation}</p>
                                <p className="text-xs opacity-75">
                                  <strong>Evidence:</strong> {rec.evidence}
                                </p>
                              </div>
                            ))
                        ) : (
                          <div className="space-y-6">
                            <div className="text-center py-8">
                              <CheckCircle className="h-12 w-12 text-green-500 mx-auto mb-4" />
                              <h3 className="text-lg font-semibold text-green-800 mb-2">No Supplement Recommendations</h3>
                              <p className="text-green-700">
                                Your lab results are within normal ranges, so no specific supplements are recommended at this time.
                              </p>
                              <p className="text-sm text-green-600 mt-2">
                                Continue maintaining a balanced diet and healthy lifestyle.
                              </p>
                            </div>
                          </div>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                </TabsContent>

                <TabsContent value="questions" className="space-y-4">
                  <Card>
                    <CardHeader>
                      <CardTitle>AI-Generated Questions for Your Doctor</CardTitle>
                      <CardDescription>Personalized questions based on your lab results</CardDescription>
                    </CardHeader>
                    <CardContent className="max-h-96 overflow-y-auto">
                      <ul className="space-y-3 text-sm">
                        {labSet.interpretation?.questions && labSet.interpretation.questions.length > 0 ? (
                          labSet.interpretation.questions.map((question: string, index: number) => (
                            <li key={index} className="flex items-start gap-2">
                              <MessageCircleQuestion className="h-4 w-4 text-primary mt-0.5 flex-shrink-0" />
                              <div>{question}</div>
                            </li>
                          ))
                        ) : (
                          <>
                            <li className="flex items-start gap-2">
                              <MessageCircleQuestion className="h-4 w-4 text-primary mt-0.5 flex-shrink-0" />
                              <div>Are there any specific dietary recommendations for someone with my lab profile?</div>
                            </li>
                            <li className="flex items-start gap-2">
                              <MessageCircleQuestion className="h-4 w-4 text-primary mt-0.5 flex-shrink-0" />
                              <div>How often should I have follow-up labs to monitor these values?</div>
                            </li>
                            <li className="flex items-start gap-2">
                              <MessageCircleQuestion className="h-4 w-4 text-primary mt-0.5 flex-shrink-0" />
                              <div>Are there any other tests you would recommend based on these results?</div>
                            </li>
                          </>
                        )}
                      </ul>
                    </CardContent>
                  </Card>
                </TabsContent>
              </Tabs>
            </div>
          </div>

          {/* Complete Lab Results */}
          {labSet.labResults && labSet.labResults.length > 0 && (
            <div className="mt-12">
              <h2 className="mb-6 text-2xl font-bold text-center">Complete Lab Results</h2>
              <p className="text-center text-muted-foreground mb-8">
                All your markers with values and reference ranges for easy comparison
              </p>
              <TooltipProvider>
                <div className="space-y-6">
                  {(() => {
                    // Group markers by category/panel
                    const groupedMarkers = labSet.labResults.reduce((acc: any, marker: any) => {
                      const category = marker.panel || 'Other'
                      if (!acc[category]) {
                        acc[category] = []
                      }
                      acc[category].push(marker)
                      return acc
                    }, {})

                    return Object.entries(groupedMarkers).map(([category, markers]: [string, any]) => (
                      <div key={category} className="space-y-4">
                        <div className="flex items-center gap-2">
                          <h3 className="text-lg font-semibold text-primary">{category}</h3>
                          <Badge variant="outline" className="text-xs">
                            {markers.length} marker{markers.length !== 1 ? 's' : ''}
                          </Badge>
                        </div>
                        <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                          {markers.map((marker: any, index: number) => {
                            // Calculate status based on reference ranges
                            const getValueStatus = (marker: any) => {
                              // Check if reference ranges are available
                              const hasRefRanges = marker.ref_range_low !== undefined || marker.ref_range_high !== undefined;

                              if (!hasRefRanges) {
                                return { status: 'unknown', color: 'bg-gray-100 text-gray-800' }
                              }

                              if (marker.ref_range_low !== undefined && marker.ref_range_high !== undefined) {
                                if (marker.value_raw >= marker.ref_range_low && marker.value_raw <= marker.ref_range_high) {
                                  return { status: 'normal', color: 'bg-green-100 text-green-800' }
                                } else if (marker.value_raw < marker.ref_range_low) {
                                  return { status: 'low', color: 'bg-yellow-100 text-yellow-800' }
                                } else {
                                  return { status: 'high', color: 'bg-red-100 text-red-800' }
                                }
                              }

                              if (marker.ref_range_low !== undefined && marker.value_raw < marker.ref_range_low) {
                                return { status: 'low', color: 'bg-yellow-100 text-yellow-800' }
                              }

                              if (marker.ref_range_high !== undefined && marker.value_raw > marker.ref_range_high) {
                                return { status: 'high', color: 'bg-red-100 text-red-800' }
                              }

                              return { status: 'normal', color: 'bg-green-100 text-green-800' }
                            }

                            const valueStatus = getValueStatus(marker)

                            const currentMarkerInfo = markerInfo[marker.code as keyof typeof markerInfo]

                            return (
                              <Tooltip key={index}>
                                <TooltipTrigger asChild>
                                  <Card className="relative hover:shadow-md transition-shadow cursor-help" onClick={() => console.log('Card clicked:', marker.name)}>
                                    <CardContent className="p-4 space-y-3">
                                      <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-2">
                                          <Activity className="h-3 w-3 text-primary" />
                                          <span className="text-sm font-medium">{marker.name}</span>
                                          <Tooltip>
                                            <TooltipTrigger asChild>
                                              <Info className="h-3 w-3 text-muted-foreground cursor-help hover:text-primary transition-colors" />
                                            </TooltipTrigger>
                                            <TooltipContent side="top" className="max-w-xs p-3 z-50 bg-white border border-gray-200 shadow-lg">
                                              <div className="space-y-2">
                                                <div>
                                                  <h4 className="font-medium text-sm text-gray-900 mb-1">{marker.name}</h4>
                                                  <p className="text-xs text-gray-500">{marker.code}</p>
                                                </div>

                                                {currentMarkerInfo ? (
                                                  <div className="space-y-2">
                                                    <div>
                                                      <h5 className="font-medium text-xs text-gray-700">What it is:</h5>
                                                      <p className="text-xs text-gray-600">{currentMarkerInfo.whatItIs}</p>
                                                    </div>
                                                    <div>
                                                      <h5 className="font-medium text-xs text-gray-700">Why it matters:</h5>
                                                      <p className="text-xs text-gray-600">{currentMarkerInfo.whyItMatters}</p>
                                                    </div>
                                                    <div>
                                                      <h5 className="font-medium text-xs text-gray-700">What affects it:</h5>
                                                      <p className="text-xs text-gray-600">{currentMarkerInfo.whatAffectsIt}</p>
                                                    </div>
                                                    <div>
                                                      <h5 className="font-medium text-xs text-gray-700">When to check with doctor:</h5>
                                                      <p className="text-xs text-gray-600">{currentMarkerInfo.whenToCheckWithDoctor}</p>
                                                    </div>
                                                  </div>
                                                ) : (
                                                  <div className="space-y-2">
                                                    <p className="text-xs text-gray-600">
                                                      <strong className="text-gray-700">What it is:</strong> {marker.name} is a laboratory test that measures specific substances in your blood.
                                                    </p>
                                                    <p className="text-xs text-gray-600">
                                                      <strong className="text-gray-700">Why it matters:</strong> This test helps doctors understand how well different parts of your body are working.
                                                    </p>
                                                    <p className="text-xs text-gray-600">
                                                      <strong className="text-gray-700">Your result:</strong> {marker.value_raw} {marker.unit_raw} 
                                                      {marker.ref_range_low !== undefined && marker.ref_range_high !== undefined
                                                        ? ` (Normal range: ${marker.ref_range_low} - ${marker.ref_range_high} ${marker.unit_raw})`
                                                        : ''
                                                      }
                                                    </p>
                                                    <p className="text-xs text-gray-600">
                                                      <strong className="text-gray-700">When to check with doctor:</strong> If your result is outside the normal range, discuss with your healthcare provider.
                                                    </p>
                                                  </div>
                                                )}
                                              </div>
                                            </TooltipContent>
                                          </Tooltip>
                                        </div>
                                        <Badge className={valueStatus.color} variant="secondary">
                                          {valueStatus.status}
                                        </Badge>
                                      </div>

                                  <div className="space-y-2">
                                    <div className="flex justify-between items-center">
                                      <span className="text-xs text-muted-foreground">Value:</span>
                                      <span className="text-sm font-semibold">
                                        {marker.value_raw} {marker.unit_raw}
                                      </span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                      <span className="text-xs text-muted-foreground">Reference:</span>
                                      <span className="text-xs">
                                        {marker.ref_range_low !== undefined && marker.ref_range_high !== undefined
                                          ? `${marker.ref_range_low} - ${marker.ref_range_high} ${marker.unit_raw}`
                                          : marker.ref_range_low !== undefined
                                            ? `> ${marker.ref_range_low} ${marker.unit_raw}`
                                            : marker.ref_range_high !== undefined
                                              ? `< ${marker.ref_range_high} ${marker.unit_raw}`
                                              : 'Not available'}
                                      </span>
                                    </div>
                                    {marker.code && (
                                      <div className="flex justify-between items-center">
                                        <span className="text-xs text-muted-foreground">Code:</span>
                                        <span className="text-xs">{marker.code}</span>
                                      </div>
                                    )}
                                  </div>
                                </CardContent>
                              </Card>
                                </TooltipTrigger>
                              </Tooltip>
                            )
                          })}
                        </div>
                      </div>
                    ))
                  })()}
                </div>
              </TooltipProvider>
            </div>
          )}

          {/* Navigation */}
          <div className="mt-12 flex items-center justify-between">
            <Button asChild variant="outline">
              <Link href="/dashboard">
                <User className="mr-2 h-4 w-4" />
                Back to Dashboard
              </Link>
            </Button>
            <div className="flex gap-2">
              <Button 
                onClick={handlePrint}
                variant="outline"
                disabled={!labSet.interpretation}
              >
                <Printer className="mr-2 h-4 w-4" />
                Print Report
              </Button>
              <Button asChild>
                <Link href="/upload">
                  <FileUp className="mr-2 h-4 w-4" />
                  Upload New Report
                </Link>
              </Button>
            </div>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="border-t bg-card/50 py-8">
        <div className="container mx-auto px-4 text-center">
          <div className="p-4 rounded-lg bg-yellow-50 border border-yellow-200 max-w-4xl mx-auto">
            <p className="text-sm text-yellow-800">
              <strong className="text-yellow-900 bg-yellow-100 px-2 py-1 rounded">
                Always consult with qualified healthcare professionals
              </strong>{" "}
              for medical advice and treatment decisions. This analysis is for educational purposes only and is not a
              substitute for professional medical consultation.
            </p>
          </div>
        </div>
      </footer>
    </div>
  )
}

