"use client"

import Link from "next/link"
import { useEffect, useState } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Alert, AlertDescription } from "@/components/ui/alert"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { useToast } from "@/hooks/use-toast"
import {
  Heart,
  AlertTriangle,
  TrendingUp,
  TrendingDown,
  Info,
  FileText,
  Lightbulb,
  MessageCircleQuestion,
  Activity,
  Droplets,
  Zap,
  Shield,
  Brain,
  Home,
  User,
  Calendar,
  FileUp,
  Loader2,
  CheckCircle,
  Printer,
} from "lucide-react"
import { useAuth } from "@/lib/auth-context"
import { useRouter } from "next/navigation"

interface LabSet {
  id: string
  name: string
  createdAt: string
  collectedAt?: string
  labResults: any[]
  interpretation: any
  markerCount: number
  panels: string[]
}

export default function LabResultDetailPage({ params }: { params: { id: string } }) {
  const router = useRouter()
  const { user, isAuthenticated, loading } = useAuth()
  const { toast } = useToast()
  const [labSet, setLabSet] = useState<LabSet | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [addingInterpretation, setAddingInterpretation] = useState(false)

  useEffect(() => {
    if (!loading && !isAuthenticated) {
      router.push("/signin")
      return
    }

    if (isAuthenticated && params.id) {
      loadLabSet()
    }
  }, [isAuthenticated, loading, params.id, router])

  const loadLabSet = async () => {
    try {
      console.log('[Results] Loading lab set with ID:', params.id)
      console.log('[Results] User authenticated:', isAuthenticated)
      console.log('[Results] User ID:', user?.id)

      // Get the lab set data first
      console.log('[Results] Making request to /api/lab-sets')
      const response = await fetch('/api/lab-sets', {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
        },
      })
      console.log('[Results] Fetch response status:', response.status)
      console.log('[Results] Fetch response ok:', response.ok)
      console.log('[Results] Fetch response url:', response.url)

      if (!response.ok) {
        const errorText = await response.text()
        console.error('[Results] API response not ok:', response.status, errorText)
        setError(`API Error: ${response.status} - ${errorText}`)
        return
      }

      const data = await response.json()
      console.log('[Results] API response data:', data)

      if (data.success) {
        console.log('[Results] Available lab sets:', data.data?.length || 0)
        const foundLabSet = data.data?.find((set: LabSet) => set.id === params.id)
        console.log('[Results] Found lab set:', foundLabSet)
        if (foundLabSet) {
          // Check if this is an old interpretation that needs enhancement
          const hasOldInterpretation = foundLabSet.interpretation && 
            foundLabSet.interpretation.summary === "Lab results have been analyzed. Please consult with your healthcare provider for detailed interpretation."

          if (hasOldInterpretation) {
            console.log('[Results] Found old interpretation, regenerating with enhanced logic...')
            // Regenerate with enhanced interpretation
            await regenerateInterpretation(foundLabSet)
          } else {
            // Set the lab set data as-is
            setLabSet(foundLabSet)
            console.log('[Results] Lab set loaded successfully:', foundLabSet.id)
          }
        } else {
          console.log('[Results] Lab set not found. Available IDs:', data.data?.map((set: LabSet) => set.id) || [])
          setError(`Lab results not found. Available IDs: ${data.data?.map((set: LabSet) => set.id).join(', ') || 'none'}`)
        }
      } else {
        console.error('[Results] API returned success: false:', data)
        setError(`API Error: ${data.message || 'Unknown error'}`)
      }
    } catch (error) {
      console.error("Error loading lab set:", error)
      setError(`Network Error: ${error instanceof Error ? error.message : 'Unknown error'}`)
    } finally {
      setIsLoading(false)
    }
  }

  const regenerateInterpretation = async (labSet: LabSet) => {
    if (addingInterpretation) {
      console.log('[Results] Already regenerating interpretation, skipping...')
      return
    }

    setAddingInterpretation(true)
    try {
      console.log('[Results] Regenerating interpretation for lab set:', labSet.id)
      console.log('[Results] Using enhanced interpretation logic with user profile data')

      // Get demographics from user profile or use defaults
      const demographics = {
        age: user?.profile?.age || 30,
        sex: user?.profile?.sex || "male",
        height: user?.profile?.height || 175, // cm
        weight: user?.profile?.weight || 70, // kg
        pregnant: false, // This would need to be added to profile if needed
        medical_conditions: user?.profile?.medical_conditions || [],
        medications: user?.profile?.medications || [],
        lifestyle: user?.profile?.lifestyle || {}
      }

      // DEBUG: Log the profile data being used
      console.log('[DEBUG] User profile data:', user?.profile)
      console.log('[DEBUG] Demographics being sent to API:', demographics)
      console.log('[DEBUG] User age from profile:', user?.profile?.age)
      console.log('[DEBUG] User sex from profile:', user?.profile?.sex)
      console.log('[DEBUG] User lifestyle from profile:', user?.profile?.lifestyle)

      // Convert lab results to the format expected by the API
      const labs = labSet.labResults.map((lab: any) => ({
        code: lab.code,
        name: lab.name,
        value: lab.value_raw,
        unit: lab.unit_raw,
        value_si: lab.value_si,
        unit_si: lab.unit_si,
        ref_range_low: lab.ref_range_low,
        ref_range_high: lab.ref_range_high,
        category: lab.category || 'Other'
      }))

      console.log('[Results] Calling /api/process-complete-safe with:', {
        demographics,
        labsCount: labs.length
      })

      // Call the same API that generates fresh interpretation
      const response = await fetch("/api/process-complete-safe", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          demographics,
          labs: labs,
          updateExistingLabSetId: labSet.id, // Update existing lab set instead of creating new one
        }),
      })

      console.log('[Results] API response status:', response.status)
      console.log('[Results] API response ok:', response.ok)

      if (!response.ok) {
        const errorData = await response.json()
        console.error('[Results] API error response:', errorData)
        throw new Error(errorData.message || "Failed to regenerate interpretation")
      }

      const processData = await response.json()
      console.log('[Results] API success response:', processData)

      if (!processData.success) {
        console.error('[Results] API returned success: false', processData)
        throw new Error(processData.message || "Processing failed")
      }

      // Update the lab set with the fresh interpretation
      const updatedLabSet = {
        ...labSet,
        interpretation: processData.data.interpretation
      }

      console.log('[Results] Setting updated lab set with fresh interpretation:', updatedLabSet)
      setLabSet(updatedLabSet)

      toast({
        title: "Enhanced Analysis Ready",
        description: "Your lab results now include personalized insights based on your profile data.",
      })

    } catch (error) {
      console.error('[Results] Error regenerating interpretation:', error)
      // If regeneration fails, still show the lab set with existing data
      setLabSet(labSet)
      toast({
        title: "Error",
        description: "Failed to regenerate interpretation. Please try again.",
        variant: "destructive",
      })
    } finally {
      setAddingInterpretation(false)
    }
  }

  // Comprehensive marker information database
  const markerInfo = {
    'RBC': {
      whatItIs: "Red Blood Cell Count - measures the number of red blood cells in your blood that carry oxygen to tissues",
      whyItMatters: "Too low → anemia risk and fatigue; too high → possible dehydration or bone marrow overactivity",
      whatAffectsIt: "Iron-rich diet, endurance training, hydration, altitude, smoking, certain medications",
      whenToCheckWithDoctor: "If values are consistently abnormal or you have symptoms like fatigue or dizziness"
    },
    'WBC': {
      whatItIs: "White Blood Cell Count - measures white blood cells that are part of your immune system and fight infections",
      whyItMatters: "High levels may indicate infection or inflammation; low levels can mean weakened immunity",
      whatAffectsIt: "Infections, stress, medications, autoimmune conditions, recent illness or vaccination",
      whenToCheckWithDoctor: "If consistently high or low, especially with fever, frequent infections, or feeling unwell"
    },
    'HGB': {
      whatItIs: "Hemoglobin - protein in red blood cells that carries oxygen throughout your body",
      whyItMatters: "Low levels may cause fatigue and weakness; high levels can indicate dehydration or other conditions",
      whatAffectsIt: "Iron intake, hydration status, altitude, smoking, exercise, blood loss, certain medications",
      whenToCheckWithDoctor: "If consistently outside normal range, experiencing fatigue, shortness of breath, or unusual weakness"
    },
    'HCT': {
      whatItIs: "Hematocrit - percentage of your blood that is made up of red blood cells",
      whyItMatters: "Helps diagnose anemia and dehydration; high levels may indicate dehydration or blood disorders",
      whatAffectsIt: "Hydration status, altitude, smoking, certain medications, blood loss, bone marrow function",
      whenToCheckWithDoctor: "If outside normal range, especially with symptoms like fatigue, dizziness, or shortness of breath"
    },
    'PLT': {
      whatItIs: "Platelet Count - measures small blood cells that help with blood clotting and wound healing",
      whyItMatters: "Too few can cause bleeding problems; too many can increase risk of blood clots",
      whatAffectsIt: "Infections, medications, autoimmune conditions, bone marrow disorders, certain cancers",
      whenToCheckWithDoctor: "If outside normal range, especially with bleeding, bruising, or clotting symptoms"
    },
    'MCV': {
      whatItIs: "Mean Corpuscular Volume - measures the average size of your red blood cells",
      whyItMatters: "Helps identify different types of anemia; small cells may indicate iron deficiency, large cells may indicate vitamin B12 or folate deficiency",
      whatAffectsIt: "Iron levels, vitamin B12, folate, alcohol consumption, certain medications, genetic conditions",
      whenToCheckWithDoctor: "If outside normal range, especially with symptoms like fatigue, weakness, or pale skin"
    },
    'MCH': {
      whatItIs: "Mean Corpuscular Hemoglobin - measures the average amount of hemoglobin in each red blood cell",
      whyItMatters: "Helps diagnose different types of anemia and provides information about red blood cell health",
      whatAffectsIt: "Iron levels, vitamin B12, folate, genetic conditions, certain medications",
      whenToCheckWithDoctor: "If outside normal range, especially with other blood count abnormalities"
