  const generatePrintReport = () => {
    if (!labSet || !labSet.interpretation) return

    let report = "LAB RESULTS ANALYSIS REPORT\n"
    report += "=" .repeat(50) + "\n\n"

    // AI Summary
    report += "AI SUMMARY\n"
    report += "-" .repeat(20) + "\n"
    report += labSet.interpretation.summary + "\n\n"

    // Key Flags
    report += "KEY FLAGS\n"
    report += "-" .repeat(20) + "\n"
    if (labSet.interpretation.flags && labSet.interpretation.flags.length > 0) {
      labSet.interpretation.flags.forEach((flag: any) => {
        if (flag.severity !== 'normal') {
          report += `• ${flag.lab_name} (${flag.severity.toUpperCase()}): ${flag.finding}\n`
          report += `  ${flag.description}\n\n`
        }
      })
    } else {
      report += "No significant flags detected.\n\n"
    }

    // Complete Lab Results
    report += "COMPLETE LAB RESULTS\n"
    report += "-" .repeat(25) + "\n"
    const groupedMarkers = labSet.labResults.reduce((acc: any, marker: any) => {
      const category = marker.panel || 'Other'
      if (!acc[category]) {
        acc[category] = []
      }
      acc[category].push(marker)
      return acc
    }, {})

    Object.entries(groupedMarkers).forEach(([category, markers]: [string, any]) => {
      report += `\n${category.toUpperCase()}:\n`
      markers.forEach((marker: any) => {
        report += `  • ${marker.name}: ${marker.value_raw} ${marker.unit_raw}\n`
      })
    })

    report += "\n" + "=" .repeat(50) + "\n"
    report += "IMPORTANT MEDICAL DISCLAIMER\n"
    report += "=" .repeat(50) + "\n"
    report += "This analysis is for educational purposes only and is not medical advice. Always consult with qualified healthcare professionals for medical decisions and interpretation of your lab results.\n"

    return report
  }

